import AsyncStorage from '@react-native-async-storage/async-storage';

const KEYS = {
  ALIYUN_ACCESS_KEY_ID: 'aliyun_access_key_id',
  ALIYUN_ACCESS_KEY_SECRET: 'aliyun_access_key_secret',
  ALIYUN_APP_KEY: 'aliyun_app_key',
  ZHIPU_API_KEY: 'zhipu_api_key',
};

export async function getConfig() {
  const [akId, akSecret, appKey, zhipuKey] = await Promise.all([
    AsyncStorage.getItem(KEYS.ALIYUN_ACCESS_KEY_ID),
    AsyncStorage.getItem(KEYS.ALIYUN_ACCESS_KEY_SECRET),
    AsyncStorage.getItem(KEYS.ALIYUN_APP_KEY),
    AsyncStorage.getItem(KEYS.ZHIPU_API_KEY),
  ]);
  return {
    aliyunAccessKeyId: akId || '',
    aliyunAccessKeySecret: akSecret || '',
    aliyunAppKey: appKey || '',
    zhipuApiKey: zhipuKey || '',
  };
}

export async function saveConfig(config: {
  aliyunAccessKeyId: string;
  aliyunAccessKeySecret: string;
  aliyunAppKey: string;
  zhipuApiKey: string;
}) {
  await Promise.all([
    AsyncStorage.setItem(KEYS.ALIYUN_ACCESS_KEY_ID, config.aliyunAccessKeyId),
    AsyncStorage.setItem(KEYS.ALIYUN_ACCESS_KEY_SECRET, config.aliyunAccessKeySecret),
    AsyncStorage.setItem(KEYS.ALIYUN_APP_KEY, config.aliyunAppKey),
    AsyncStorage.setItem(KEYS.ZHIPU_API_KEY, config.zhipuApiKey),
  ]);
}

export function isConfigValid(config: Awaited<ReturnType<typeof getConfig>>) {
  return !!(config.aliyunAccessKeyId && config.aliyunAccessKeySecret && config.aliyunAppKey && config.zhipuApiKey);
}

import crypto from 'crypto-js';
import RNFS from 'react-native-fs';

// 阿里云语音识别 - 一句话识别 RESTful API
// https://help.aliyun.com/document_detail/92131.html

function createToken(accessKeyId: string, accessKeySecret: string): string {
  // 简化的token获取 - 实际使用阿里云NLS的RESTful接口
  const timestamp = new Date().toISOString().replace(/[-:]/g, '').replace(/\.\d+/, '');
  const nonce = Math.random().toString(36).substring(2);
  const params: Record<string, string> = {
    AccessKeyId: accessKeyId,
    Action: 'CreateToken',
    Format: 'JSON',
    RegionId: 'cn-shanghai',
    SignatureMethod: 'HMAC-SHA1',
    SignatureNonce: nonce,
    SignatureVersion: '1.0',
    Timestamp: timestamp,
    Version: '2019-02-28',
  };

  const sortedKeys = Object.keys(params).sort();
  const canonicalized = sortedKeys
    .map(k => `${encodeURIComponent(k)}=${encodeURIComponent(params[k])}`)
    .join('&');
  const stringToSign = `GET&${encodeURIComponent('/')}&${encodeURIComponent(canonicalized)}`;
  const signature = crypto.HmacSHA1(stringToSign, accessKeySecret + '&').toString(crypto.enc.Base64);
  params.Signature = signature;

  const query = Object.keys(params)
    .map(k => `${encodeURIComponent(k)}=${encodeURIComponent(params[k])}`)
    .join('&');
  return `https://nls-meta.cn-shanghai.aliyuncs.com/?${query}`;
}

export async function transcribeAudio(
  filePath: string,
  accessKeyId: string,
  accessKeySecret: string,
  appKey: string,
): Promise<string> {
  // Step 1: 获取Token
  const tokenUrl = createToken(accessKeyId, accessKeySecret);
  const tokenResp = await fetch(tokenUrl);
  const tokenData = await tokenResp.json();
  const token = tokenData?.Token?.Id;
  if (!token) {
    throw new Error('获取阿里云Token失败: ' + JSON.stringify(tokenData));
  }

  // Step 2: 读取音频文件
  const audioBase64 = await RNFS.readFile(filePath, 'base64');
  const audioBytes = Uint8Array.from(atob(audioBase64), c => c.charCodeAt(0));

  // Step 3: 调用录音文件识别接口（长音频）
  // 先上传获取task
  const submitResp = await fetch(
    'https://filetrans.cn-shanghai.aliyuncs.com/api/v1/transcritions',
    {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-NLS-Token': token,
      },
      body: JSON.stringify({
        appkey: appKey,
        file_link: '', // 需要文件URL，改用一句话识别或流式
      }),
    },
  );

  // 使用一句话识别（适合60秒以内）或实时转写
  // 这里用更通用的方案：将音频分段用一句话识别
  const url = `https://nls-gateway-cn-shanghai.aliyuncs.com/stream/v1/asr?appkey=${appKey}&format=pcm&sample_rate=16000&enable_punctuation_prediction=true&enable_inverse_text_normalization=true`;

  const resp = await fetch(url, {
    method: 'POST',
    headers: {
      'X-NLS-Token': token,
      'Content-Type': 'application/octet-stream',
    },
    body: audioBytes,
  });

  const result = await resp.json();
  if (result.status === 20000000 && result.result) {
    return result.result;
  }

  throw new Error('语音识别失败: ' + JSON.stringify(result));
}

// 智谱GLM API - 语义对比
// https://open.bigmodel.cn/dev/api

export interface DiffItem {
  docText: string;
  audioText: string;
  type: 'mismatch' | 'missing_in_audio' | 'extra_in_audio';
  position: number; // 在文档中的大致位置（段落索引）
}

export interface CompareResult {
  diffs: DiffItem[];
  summary: string;
}

export async function compareTexts(
  audioText: string,
  docText: string,
  apiKey: string,
): Promise<CompareResult> {
  const prompt = `你是一个专业的文档校对助手。请对比以下两段文字，找出所有不一致的地方。

【录音转写文字】
${audioText}

【Word文档原文】
${docText}

请以JSON格式返回对比结果，格式如下：
{
  "diffs": [
    {
      "docText": "文档中的原文片段",
      "audioText": "录音中对应的文字（如果有）",
      "type": "mismatch 或 missing_in_audio 或 extra_in_audio",
      "position": 段落索引号（从0开始）
    }
  ],
  "summary": "总结说明，共发现多少处不一致"
}

注意：
- mismatch: 两边都有但内容不同
- missing_in_audio: 文档有但录音没提到
- extra_in_audio: 录音有但文档没有
- 语义相同但表述不同的不算差异（如"价格高"和"价格偏高"算一致）
- 口语化表达和书面表达的差异不算差异
- 只返回JSON，不要其他内容`;

  const resp = await fetch('https://open.bigmodel.cn/api/paas/v4/chat/completions', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model: 'glm-4-flash',
      messages: [{role: 'user', content: prompt}],
      temperature: 0.1,
    }),
  });

  const data = await resp.json();
  const content = data?.choices?.[0]?.message?.content || '';

  // 提取JSON
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (!jsonMatch) {
    return {diffs: [], summary: '对比完成，未发现差异或解析失败'};
  }

  try {
    return JSON.parse(jsonMatch[0]);
  } catch {
    return {diffs: [], summary: '对比结果解析失败: ' + content.substring(0, 200)};
  }
}

import JSZip from 'jszip';
import RNFS from 'react-native-fs';

// 解析 .docx 文件提取纯文本（按段落）
export async function parseDocx(filePath: string): Promise<string[]> {
  const base64 = await RNFS.readFile(filePath, 'base64');
  const zip = await JSZip.loadAsync(base64, {base64: true});
  const docXml = await zip.file('word/document.xml')?.async('string');
  if (!docXml) {
    throw new Error('无法读取Word文档内容');
  }

  // 提取段落文本
  const paragraphs: string[] = [];
  const pRegex = /<w:p[\s>][\s\S]*?<\/w:p>/g;
  let pMatch;
  while ((pMatch = pRegex.exec(docXml)) !== null) {
    const pXml = pMatch[0];
    // 提取所有 <w:t> 标签内的文字
    const tRegex = /<w:t[^>]*>([\s\S]*?)<\/w:t>/g;
    let text = '';
    let tMatch;
    while ((tMatch = tRegex.exec(pXml)) !== null) {
      text += tMatch[1];
    }
    if (text.trim()) {
      paragraphs.push(text.trim());
    }
  }

  return paragraphs;
}

// 段落数组合并为全文
export function paragraphsToText(paragraphs: string[]): string {
  return paragraphs.join('\n');
}

import JSZip from 'jszip';
import RNFS from 'react-native-fs';
import {DiffItem} from './zhipuCompare';

// 生成标红差异的 .docx 文件
export async function generateDiffDocx(
  originalFilePath: string,
  diffs: DiffItem[],
): Promise<string> {
  const base64 = await RNFS.readFile(originalFilePath, 'base64');
  const zip = await JSZip.loadAsync(base64, {base64: true});
  let docXml = (await zip.file('word/document.xml')?.async('string')) || '';

  // 构建差异位置索引
  const diffByPosition = new Map<number, DiffItem[]>();
  for (const diff of diffs) {
    const pos = diff.position;
    if (!diffByPosition.has(pos)) {
      diffByPosition.set(pos, []);
    }
    diffByPosition.get(pos)!.push(diff);
  }

  // 找到所有段落并在有差异的段落后插入红色标注
  const pRegex = /<w:p[\s>][\s\S]*?<\/w:p>/g;
  let paragraphIndex = 0;
  let offset = 0;
  let match;
  const insertions: {pos: number; text: string}[] = [];

  // 先收集所有非空段落的位置
  const pMatches: {index: number; length: number; pIdx: number}[] = [];
  while ((match = pRegex.exec(docXml)) !== null) {
    const tRegex = /<w:t[^>]*>([\s\S]*?)<\/w:t>/g;
    let hasText = false;
    let t;
    while ((t = tRegex.exec(match[0])) !== null) {
      if (t[1].trim()) {hasText = true; break;}
    }
    if (hasText) {
      pMatches.push({index: match.index, length: match[0].length, pIdx: paragraphIndex});
      paragraphIndex++;
    }
  }

  // 在有差异的段落后插入红色注释段落
  for (let i = pMatches.length - 1; i >= 0; i--) {
    const pm = pMatches[i];
    const itemDiffs = diffByPosition.get(pm.pIdx);
    if (!itemDiffs || itemDiffs.length === 0) continue;

    for (const diff of itemDiffs) {
      let label = '';
      if (diff.type === 'mismatch') {
        label = `【差异】文档: "${diff.docText}" → 录音: "${diff.audioText}"`;
      } else if (diff.type === 'missing_in_audio') {
        label = `【录音缺失】"${diff.docText}"`;
      } else {
        label = `【录音多出】"${diff.audioText}"`;
      }

      const redParagraph = `<w:p><w:pPr><w:rPr><w:color w:val="FF0000"/><w:b/></w:rPr></w:pPr><w:r><w:rPr><w:color w:val="FF0000"/><w:b/></w:rPr><w:t xml:space="preserve">${escapeXml(label)}</w:t></w:r></w:p>`;

      const insertPos = pm.index + pm.length;
      docXml = docXml.slice(0, insertPos) + redParagraph + docXml.slice(insertPos);
    }
  }

  zip.file('word/document.xml', docXml);
  const outputBase64 = await zip.generateAsync({type: 'base64'});
  const outputPath = `${RNFS.CachesDirectoryPath}/对比结果_${Date.now()}.docx`;
  await RNFS.writeFile(outputPath, outputBase64, 'base64');
  return outputPath;
}

function escapeXml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

