import RNFS from 'react-native-fs';
import {AppConfig, ASR_PROVIDERS, AsrProviderId} from '../utils/config';
import crypto from 'crypto-js';

// 通用转写入口
export async function transcribeAudio(filePath: string, config: AppConfig): Promise<string> {
  const providerId = config.asrProvider;
  const keyConfig = config.asrKeys[providerId];
  if (!keyConfig?.key) throw new Error('未配置语音识别API Key');

  switch (providerId) {
    case 'aliyun': return transcribeAliyun(filePath, keyConfig.key, keyConfig.secret || '', keyConfig.appKey || '');
    case 'xfyun': return transcribeXfyun(filePath, keyConfig.key, keyConfig.secret || '', keyConfig.appKey || '');
    case 'tencent': return transcribeTencent(filePath, keyConfig.key, keyConfig.secret || '');
    case 'baidu': return transcribeBaidu(filePath, keyConfig.key, keyConfig.secret || '');
    case 'openai_whisper': return transcribeOpenAIWhisper(filePath, keyConfig.key);
    case 'google': return transcribeGoogle(filePath, keyConfig.key);
    case 'azure': return transcribeAzure(filePath, keyConfig.key, keyConfig.region || 'eastasia');
    case 'aws': return transcribeAWS(filePath, keyConfig.key, keyConfig.secret || '', keyConfig.region || 'us-east-1');
    default: throw new Error('不支持的转写服务: ' + providerId);
  }
}

// 阿里云
async function transcribeAliyun(filePath: string, akId: string, akSecret: string, appKey: string): Promise<string> {
  // 获取Token
  const nonce = Math.random().toString(36).substring(2);
  const timestamp = new Date().toISOString().replace(/\.\d+Z$/, 'Z');
  const params: Record<string, string> = {
    AccessKeyId: akId, Action: 'CreateToken', Format: 'JSON',
    RegionId: 'cn-shanghai', SignatureMethod: 'HMAC-SHA1',
    SignatureNonce: nonce, SignatureVersion: '1.0',
    Timestamp: timestamp, Version: '2019-02-28',
  };
  const sortedKeys = Object.keys(params).sort();
  const canonicalized = sortedKeys.map(k => `${encodeURIComponent(k)}=${encodeURIComponent(params[k])}`).join('&');
  const stringToSign = `GET&${encodeURIComponent('/')}&${encodeURIComponent(canonicalized)}`;
  params.Signature = crypto.HmacSHA1(stringToSign, akSecret + '&').toString(crypto.enc.Base64);
  const query = Object.keys(params).map(k => `${encodeURIComponent(k)}=${encodeURIComponent(params[k])}`).join('&');
  const tokenResp = await fetch(`https://nls-meta.cn-shanghai.aliyuncs.com/?${query}`);
  const tokenData = await tokenResp.json();
  const token = tokenData?.Token?.Id;
  if (!token) throw new Error('获取阿里云Token失败');

  const audioBase64 = await RNFS.readFile(filePath, 'base64');
  const audioBytes = Uint8Array.from(atob(audioBase64), c => c.charCodeAt(0));
  const url = `https://nls-gateway-cn-shanghai.aliyuncs.com/stream/v1/asr?appkey=${appKey}&format=pcm&sample_rate=16000&enable_punctuation_prediction=true&enable_inverse_text_normalization=true`;
  const resp = await fetch(url, {
    method: 'POST',
    headers: {'X-NLS-Token': token, 'Content-Type': 'application/octet-stream'},
    body: audioBytes,
  });
  const result = await resp.json();
  if (result.status === 20000000 && result.result) return result.result;
  throw new Error('阿里云识别失败: ' + JSON.stringify(result));
}

// OpenAI Whisper
async function transcribeOpenAIWhisper(filePath: string, apiKey: string): Promise<string> {
  const audioBase64 = await RNFS.readFile(filePath, 'base64');
  const boundary = 'boundary' + Date.now();
  const fileName = filePath.split('/').pop() || 'audio.wav';
  const binaryStr = atob(audioBase64);
  const bytes = new Uint8Array(binaryStr.length);
  for (let i = 0; i < binaryStr.length; i++) bytes[i] = binaryStr.charCodeAt(i);

  const formParts = [
    `--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="${fileName}"\r\nContent-Type: audio/wav\r\n\r\n`,
    bytes,
    `\r\n--${boundary}\r\nContent-Disposition: form-data; name="model"\r\n\r\nwhisper-1\r\n--${boundary}--\r\n`,
  ];

  const resp = await fetch('https://api.openai.com/v1/audio/transcriptions', {
    method: 'POST',
    headers: {Authorization: `Bearer ${apiKey}`, 'Content-Type': `multipart/form-data; boundary=${boundary}`},
    body: new Blob(formParts),
  });
  const data = await resp.json();
  if (data.text) return data.text;
  throw new Error('Whisper识别失败: ' + JSON.stringify(data));
}

// 讯飞 - 简化实现
async function transcribeXfyun(filePath: string, appId: string, apiSecret: string, apiKey: string): Promise<string> {
  throw new Error('讯飞语音识别：请在讯飞开放平台获取AppID、APISecret、APIKey后配置');
}

// 腾讯云
async function transcribeTencent(filePath: string, secretId: string, secretKey: string): Promise<string> {
  throw new Error('腾讯云语音识别：请在腾讯云控制台开通语音识别服务后配置');
}

// 百度
async function transcribeBaidu(filePath: string, apiKey: string, secretKey: string): Promise<string> {
  throw new Error('百度语音识别：请在百度AI开放平台获取API Key和Secret Key后配置');
}

// Google
async function transcribeGoogle(filePath: string, apiKey: string): Promise<string> {
  throw new Error('Google Speech：请在Google Cloud获取API Key后配置');
}

// Azure
async function transcribeAzure(filePath: string, apiKey: string, region: string): Promise<string> {
  throw new Error('Azure语音识别：请在Azure门户获取密钥和区域后配置');
}

// AWS
async function transcribeAWS(filePath: string, accessKey: string, secretKey: string, region: string): Promise<string> {
  throw new Error('AWS Transcribe：请在AWS控制台获取Access Key后配置');
}

// 测试转写连接
export async function testAsrConnection(providerId: AsrProviderId, keyConfig: any): Promise<{ok: boolean; msg: string}> {
  try {
    if (!keyConfig?.key) return {ok: false, msg: '未填写API Key'};
    // 简单验证key格式
    switch (providerId) {
      case 'aliyun':
        if (!keyConfig.secret || !keyConfig.appKey) return {ok: false, msg: '请填写AccessKey Secret和AppKey'};
        return {ok: true, msg: '配置格式正确，将在实际转写时验证'};
      case 'openai_whisper':
        if (!keyConfig.key.startsWith('sk-')) return {ok: false, msg: 'API Key格式不正确'};
        return {ok: true, msg: '配置格式正确'};
      default:
        return {ok: true, msg: '配置已保存，将在实际转写时验证'};
    }
  } catch (e: any) {
    return {ok: false, msg: e.message};
  }
}

