  // 简化的token获取 - 实际使用阿里云NLS的RESTful接口
  const timestamp = new Date().toISOString().replace(/[-:]/g, '').replace(/\.\d+/, '');
  const nonce = Math.random().toString(36).substring(2);
  const params: Record<string, string> = {
    AccessKeyId: accessKeyId,
    Action: 'CreateToken',
    Format: 'JSON',
    RegionId: 'cn-shanghai',
    SignatureMethod: 'HMAC-SHA1',
    SignatureNonce: nonce,
    SignatureVersion: '1.0',
    Timestamp: timestamp,
    Version: '2019-02-28',
  };

  const sortedKeys = Object.keys(params).sort();
  const canonicalized = sortedKeys
    .map(k => `${encodeURIComponent(k)}=${encodeURIComponent(params[k])}`)
    .join('&');
  const stringToSign = `GET&${encodeURIComponent('/')}&${encodeURIComponent(canonicalized)}`;
  const signature = crypto.HmacSHA1(stringToSign, accessKeySecret + '&').toString(crypto.enc.Base64);
  params.Signature = signature;

  const query = Object.keys(params)
    .map(k => `${encodeURIComponent(k)}=${encodeURIComponent(params[k])}`)
    .join('&');
  return `https://nls-meta.cn-shanghai.aliyuncs.com/?${query}`;
}

export async function transcribeAudio(
  filePath: string,
  accessKeyId: string,
  accessKeySecret: string,
  appKey: string,
): Promise<string> {
  // Step 1: 获取Token
  const tokenUrl = createToken(accessKeyId, accessKeySecret);
  const tokenResp = await fetch(tokenUrl);
  const tokenData = await tokenResp.json();
  const token = tokenData?.Token?.Id;
  if (!token) {
    throw new Error('获取阿里云Token失败: ' + JSON.stringify(tokenData));
  }

  // Step 2: 读取音频文件
  const audioBase64 = await RNFS.readFile(filePath, 'base64');
  const audioBytes = Uint8Array.from(atob(audioBase64), c => c.charCodeAt(0));

  // Step 3: 调用录音文件识别接口（长音频）
  // 先上传获取task
  const submitResp = await fetch(
    'https://filetrans.cn-shanghai.aliyuncs.com/api/v1/transcritions',
    {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-NLS-Token': token,
      },
      body: JSON.stringify({
        appkey: appKey,
        file_link: '', // 需要文件URL，改用一句话识别或流式
      }),
    },
  );

  // 使用一句话识别（适合60秒以内）或实时转写
  // 这里用更通用的方案：将音频分段用一句话识别
  const url = `https://nls-gateway-cn-shanghai.aliyuncs.com/stream/v1/asr?appkey=${appKey}&format=pcm&sample_rate=16000&enable_punctuation_prediction=true&enable_inverse_text_normalization=true`;

  const resp = await fetch(url, {
    method: 'POST',
    headers: {
      'X-NLS-Token': token,
      'Content-Type': 'application/octet-stream',
    },
    body: audioBytes,
  });

  const result = await resp.json();
  if (result.status === 20000000 && result.result) {
    return result.result;
  }

  throw new Error('语音识别失败: ' + JSON.stringify(result));
}

