import React, {useState, useEffect} from 'react';
import {View, Text, TextInput, TouchableOpacity, StyleSheet, Alert, ScrollView} from 'react-native';
import {getConfig, saveConfig} from '../utils/config';

export default function SettingsScreen({navigation}: any) {
  const [akId, setAkId] = useState('');
  const [akSecret, setAkSecret] = useState('');
  const [appKey, setAppKey] = useState('');
  const [zhipuKey, setZhipuKey] = useState('');

  useEffect(() => {
    getConfig().then(c => {
      setAkId(c.aliyunAccessKeyId);
      setAkSecret(c.aliyunAccessKeySecret);
      setAppKey(c.aliyunAppKey);
      setZhipuKey(c.zhipuApiKey);
    });
  }, []);

  const save = async () => {
    if (!akId || !akSecret || !appKey || !zhipuKey) {
      Alert.alert('提示', '请填写所有字段');
      return;
    }
    await saveConfig({
      aliyunAccessKeyId: akId,
      aliyunAccessKeySecret: akSecret,
      aliyunAppKey: appKey,
      zhipuApiKey: zhipuKey,
    });
    Alert.alert('成功', '设置已保存', [
      {text: '确定', onPress: () => navigation.goBack()},
    ]);
  };

  return (
    <ScrollView style={styles.container}>
      <Text style={styles.sectionTitle}>阿里云语音识别</Text>
      <Text style={styles.label}>AccessKey ID</Text>
      <TextInput style={styles.input} value={akId} onChangeText={setAkId} placeholder="输入AccessKey ID" />
      <Text style={styles.label}>AccessKey Secret</Text>
      <TextInput style={styles.input} value={akSecret} onChangeText={setAkSecret} placeholder="输入AccessKey Secret" secureTextEntry />
      <Text style={styles.label}>AppKey</Text>
      <TextInput style={styles.input} value={appKey} onChangeText={setAppKey} placeholder="输入语音识别AppKey" />

      <Text style={[styles.sectionTitle, {marginTop: 24}]}>智谱AI</Text>
      <Text style={styles.label}>API Key</Text>
      <TextInput style={styles.input} value={zhipuKey} onChangeText={setZhipuKey} placeholder="输入智谱API Key" secureTextEntry />

      <TouchableOpacity style={styles.saveBtn} onPress={save}>
        <Text style={styles.saveBtnText}>保存设置</Text>
      </TouchableOpacity>
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  container: {flex: 1, padding: 20, backgroundColor: '#f5f5f5'},
  sectionTitle: {fontSize: 18, fontWeight: '600', color: '#333', marginBottom: 12},
  label: {fontSize: 14, color: '#666', marginBottom: 4, marginTop: 8},
  input: {
    backgroundColor: '#fff', borderWidth: 1, borderColor: '#e0e0e0',
    borderRadius: 8, padding: 12, fontSize: 14, color: '#333',
  },
  saveBtn: {
    backgroundColor: '#1a73e8', padding: 16, borderRadius: 12,
    alignItems: 'center', marginTop: 32, marginBottom: 32,
  },
  saveBtnText: {color: '#fff', fontSize: 16, fontWeight: '600'},
});

