import React, {useState, useCallback} from 'react';
import {View, Text, TouchableOpacity, StyleSheet, Alert, ActivityIndicator} from 'react-native';
import DocumentPicker from 'react-native-document-picker';
import {getConfig, isConfigValid} from '../utils/config';
import {transcribeAudio} from '../services/aliyunAsr';
import {parseDocx, paragraphsToText} from '../services/docxParser';
import {compareTexts} from '../services/zhipuCompare';
import {generateDiffDocx} from '../services/docxGenerator';

export default function HomeScreen({navigation}: any) {
  const [audioFile, setAudioFile] = useState<any>(null);
  const [docFile, setDocFile] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [status, setStatus] = useState('');

  const pickAudio = useCallback(async () => {
    try {
      const res = await DocumentPicker.pickSingle({type: DocumentPicker.types.audio});
      setAudioFile(res);
    } catch (e: any) {
      if (!DocumentPicker.isCancel(e)) Alert.alert('错误', e.message);
    }
  }, []);

  const pickDoc = useCallback(async () => {
    try {
      const res = await DocumentPicker.pickSingle({
        type: [DocumentPicker.types.docx, DocumentPicker.types.doc],
      });
      setDocFile(res);
    } catch (e: any) {
      if (!DocumentPicker.isCancel(e)) Alert.alert('错误', e.message);
    }
  }, []);

  const startCompare = useCallback(async () => {
    if (!audioFile || !docFile) {
      Alert.alert('提示', '请先选择录音和Word文档');
      return;
    }

    const config = await getConfig();
    if (!isConfigValid(config)) {
      Alert.alert('提示', '请先在设置中配置API密钥', [
        {text: '去设置', onPress: () => navigation.navigate('Settings')},
      ]);
      return;
    }

    setLoading(true);
    try {
      // Step 1: 转写录音
      setStatus('正在转写录音...');
      const audioText = await transcribeAudio(
        audioFile.uri,
        config.aliyunAccessKeyId,
        config.aliyunAccessKeySecret,
        config.aliyunAppKey,
      );

      // Step 2: 解析Word文档
      setStatus('正在解析文档...');
      const paragraphs = await parseDocx(docFile.uri);
      const docText = paragraphsToText(paragraphs);

      // Step 3: 语义对比
      setStatus('正在对比内容...');
      const result = await compareTexts(audioText, docText, config.zhipuApiKey);

      // Step 4: 生成标红Word
      setStatus('正在生成对比文档...');
      const outputPath = await generateDiffDocx(docFile.uri, result.diffs);

      setLoading(false);
      setStatus('');
      navigation.navigate('Result', {
        outputPath,
        summary: result.summary,
        diffCount: result.diffs.length,
        audioText,
        docText,
      });
    } catch (e: any) {
      setLoading(false);
      setStatus('');
      Alert.alert('处理失败', e.message);
    }
  }, [audioFile, docFile, navigation]);

  return (
    <View style={styles.container}>
      <Text style={styles.title}>选择文件</Text>

      <TouchableOpacity style={styles.fileBtn} onPress={pickAudio}>
        <Text style={styles.fileBtnIcon}>🎤</Text>
        <Text style={styles.fileBtnText}>
          {audioFile ? audioFile.name : '选择录音文件'}
        </Text>
      </TouchableOpacity>

      <TouchableOpacity style={styles.fileBtn} onPress={pickDoc}>
        <Text style={styles.fileBtnIcon}>📄</Text>
        <Text style={styles.fileBtnText}>
          {docFile ? docFile.name : '选择Word文档'}
        </Text>
      </TouchableOpacity>

      {loading ? (
        <View style={styles.loadingBox}>
          <ActivityIndicator size="large" color="#1a73e8" />
          <Text style={styles.statusText}>{status}</Text>
        </View>
      ) : (
        <TouchableOpacity
          style={[styles.startBtn, (!audioFile || !docFile) && styles.startBtnDisabled]}
          onPress={startCompare}>
          <Text style={styles.startBtnText}>开始对比</Text>
        </TouchableOpacity>
      )}

      <TouchableOpacity
        style={styles.settingsLink}
        onPress={() => navigation.navigate('Settings')}>
        <Text style={styles.settingsText}>⚙️ API设置</Text>
      </TouchableOpacity>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {flex: 1, padding: 20, backgroundColor: '#f5f5f5'},
  title: {fontSize: 20, fontWeight: '600', marginBottom: 24, textAlign: 'center', color: '#333'},
  fileBtn: {
    flexDirection: 'row', alignItems: 'center', backgroundColor: '#fff',
    padding: 16, borderRadius: 12, marginBottom: 12,
    borderWidth: 1, borderColor: '#e0e0e0', borderStyle: 'dashed',
  },
  fileBtnIcon: {fontSize: 24, marginRight: 12},
  fileBtnText: {fontSize: 16, color: '#666', flex: 1},
  startBtn: {
    backgroundColor: '#1a73e8', padding: 16, borderRadius: 12,
    alignItems: 'center', marginTop: 24,
  },
  startBtnDisabled: {backgroundColor: '#ccc'},
  startBtnText: {color: '#fff', fontSize: 18, fontWeight: '600'},
  loadingBox: {alignItems: 'center', marginTop: 24},
  statusText: {marginTop: 12, fontSize: 14, color: '#666'},
  settingsLink: {alignItems: 'center', marginTop: 32},
  settingsText: {fontSize: 14, color: '#888'},
});
